        tileLen_ = tileLength;
        d0_ = d0;
        d1_ = d1;
        d2_ = d2;
        dim_ = dim;

        xGm_.SetGlobalBuffer((__gm__ float*)x, d0_ * d1_ * d2_);
        yGm_.SetGlobalBuffer((__gm__ int64_t*)y, totalOutputLen_);

